// C3: Physical Sensing Components
instance MotorEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Motor encoder attached directly on permanent magnet synchronous motor to measure motor shaft position."
    DTDFVocab:producedData MotorEncoderDataTransmitted
]

instance GearboxEncoderSensor : DTDFVocab:SensingComponent [
    base:desc "Secondary encoder on gearbox to measure gearwheel position."
    DTDFVocab:producedData GearboxEncoderDataTransmitted
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring motor current for torque estimation."
    DTDFVocab:producedData MotorCurrentDataTransmitted
]

// C2: Data Transmitted via MQTT
instance MotorEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoderSensor
]

instance GearboxEncoderDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoderSensor
]

instance MotorCurrentDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

// C10: Data (sensor data fed into models and dashboards)
instance MotorEncoderData : DTDFVocab:Data [
    base:desc "Encoder pulse data for motor shaft position."
    DTDFVocab:fromData MotorEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkModelEnabler, AASEnabler, DashboardEnabler
]

instance GearboxEncoderData : DTDFVocab:Data [
    base:desc "Encoder pulse data for gearwheel position."
    DTDFVocab:fromData GearboxEncoderDataTransmitted
    DTDFVocab:inputTo SimulinkModelEnabler, AASEnabler, DashboardEnabler
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Motor current measurements."
    DTDFVocab:fromData MotorCurrentDataTransmitted
    DTDFVocab:inputTo SimulinkModelEnabler, AASEnabler
]

// C10: Models
instance StructuralSysMLModel : DTDFVocab:Model [
    base:desc "Structural SysML model of MABI MAX 100 robot first axis."
    DTDFVocab:inputTo SysMLEnabler
]

instance SimulinkSimulationModel : DTDFVocab:Model [
    base:desc "Simulink model simulating motor, gearwheel, and gearbox dynamics for friction estimation."
    DTDFVocab:inputTo SimulinkModelEnabler
]

// C11: Enablers
instance SysMLEnabler : DTDFVocab:Enabler [
    base:desc "SysML modelling enabler for model-based design."
    DTDFVocab:enables ModelingService
]

instance SimulinkModelEnabler : DTDFVocab:Enabler [
    base:desc "Simulink model enabler executing the Simulink simulation for friction estimation."
    DTDFVocab:enables FrictionEstimationService, ControllerUpdateService
]

instance MQTTBrokerEnabler : DTDFVocab:Enabler [
    base:desc "MQTT broker enabler facilitating MQTT data streaming of sensor signals."
    DTDFVocab:enables DataAggregationService
]

instance DashboardEnabler : DTDFVocab:Enabler [
    base:desc "Web dashboard enabler providing live plots and visualization."
    DTDFVocab:enables DashboardVisualizationService
]

instance AASEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell enabler managing metadata linkage."
    DTDFVocab:enables PerformanceMonitoringService
]

// C6: Services
instance DataAggregationService : DTDFVocab:Service [
    base:desc "Real-time data aggregation and abstraction service collecting sensor streams via MQTT."
    DTDFVocab:provides DataAggregationInsight
]

instance FrictionEstimationService : DTDFVocab:Service [
    base:desc "Continuous friction estimation service for the first axis, computing torque, angular velocity, and acceleration."
    DTDFVocab:provides FrictionParameterExtractionInsight
]

instance DashboardVisualizationService : DTDFVocab:Service [
    base:desc "Visualization dashboard service presenting live plots of measured and simulated signals."
    DTDFVocab:provides VisualizationInsight
]

instance PerformanceMonitoringService : DTDFVocab:Service [
    base:desc "Performance monitoring service supporting controller parameter updates."
    DTDFVocab:provides MaintenanceScheduleInsight
]

