    base:desc "Informing maintenance schedules by analyzing friction trends."
]

instance VisualizationInsight : DTDFVocab:Insight [
    base:desc "Live visualization of measured and simulated signals on dashboard."
]

instance DataAggregationInsight : DTDFVocab:Insight [
    base:desc "Aggregation and abstraction of real-time sensor data streams."
]

instance ModelInsight : DTDFVocab:Insight [
    base:desc "Structural insight derived from SysML model representation."
]

