]

instance twinning_time_scale : DTDFVocab:TimeScale [
    base:desc "Real‑time, continuous data acquisition and processing; the digital shadow is updated in sync with the robot’s sampling period (typically in the kHz range of the CNC controller)."
]

instance dt_constellation : DTDFVocab:Constellation [
    base:desc "A digital shadow comprised of a processing component (Simulink simulation models), data‑calculation models (friction models), data traces (measured and simulated), an AAS for asset description, and a dashboard for visualization; all orchestrated by a central controller."
]

